const COURTS = [
  { id: 1, name: 'Riverside Park Court', distance: '0.3 km', surface: 'asphalt', lighting: true, crowd: 'low', rating: 4.2, reviews: 38 },
  { id: 2, name: 'Olympic Park Indoor', distance: '1.2 km', surface: 'hardwood', lighting: true, crowd: 'medium', rating: 4.7, reviews: 124 },
  { id: 3, name: 'Hangang Court B', distance: '2.1 km', surface: 'asphalt', lighting: false, crowd: 'high', rating: 3.8, reviews: 57 },
  { id: 4, name: 'Mapo Sports Complex', distance: '3.5 km', surface: 'hardwood', lighting: true, crowd: 'low', rating: 4.5, reviews: 89 },
];

function CourtMapView({ courts, selected, onSelect }) {
  return (
    <div data-dg-component="courtMapView" className="h-[140px] bg-gradient-to-br from-blue-100 to-sky-200 relative flex items-center justify-center">
      <div className="text-[13px] text-slate-500 font-medium">🗺️ Map View</div>
      {courts.map((c, i) => (
        <div key={c.id} onClick={() => onSelect(selected === c.id ? null : c.id)}
          className={`absolute w-8 h-8 border-2 border-blue-500 cursor-pointer shadow-md -rotate-45 ${selected === c.id ? 'bg-blue-500' : 'bg-white'}`}
          style={{ borderRadius: '50% 50% 50% 0', top: 20 + (i % 2) * 50, left: 60 + i * 65 }}>
          <div className="rotate-45 text-center text-sm leading-7">🏀</div>
        </div>
      ))}
    </div>
  );
}

function ApplyCourtFilters({ filter, onChange }) {
  return (
    <div data-dg-component="applyCourtFilters" className="flex gap-2 overflow-x-auto pb-3" style={{ scrollbarWidth: 'none' }}>
      {[
        { key: 'surface', label: 'Surface', options: ['all', 'asphalt', 'hardwood'] },
        { key: 'lighting', label: '💡 Lights', options: ['all', 'yes', 'no'] },
        { key: 'crowd', label: 'Crowd', options: ['all', 'low', 'medium', 'high'] },
      ].map(f => (
        <select key={f.key} value={filter[f.key]} onChange={e => onChange(prev => ({ ...prev, [f.key]: e.target.value }))}
          className="shrink-0 border-[1.5px] border-slate-200 rounded-full px-3 py-[6px] text-xs text-gray-700 bg-white cursor-pointer outline-none">
          {f.options.map(o => <option key={o} value={o}>{o === 'all' ? f.label + ' (all)' : o}</option>)}
        </select>
      ))}
    </div>
  );
}

function CourtList({ courts, selected, onSelect, favorites, onToggleFav }) {
  const crowdClasses = { low: 'bg-emerald-50 text-emerald-500', medium: 'bg-amber-50 text-amber-400', high: 'bg-red-50 text-red-500' };
  const crowdLabel = { low: 'Quiet', medium: 'Busy', high: 'Crowded' };
  return (
    <div data-dg-component="courtList" className="px-4 pt-3 pb-6">
      <div className="text-[13px] font-semibold text-slate-500 mb-[10px]">{courts.length} COURTS FOUND</div>
      {courts.map(court => (
        <div key={court.id} onClick={() => onSelect(selected === court.id ? null : court.id)}
          className={`bg-white rounded-2xl p-4 mb-[10px] cursor-pointer transition-shadow duration-200 ${selected === court.id ? 'ring-2 ring-blue-500' : 'shadow-sm'}`}>
          <div className="flex justify-between items-start">
            <div className="flex-1">
              <div className="text-[15px] font-bold text-slate-900">{court.name}</div>
              <div className="text-xs text-slate-400 mt-0.5">{court.distance} away · {court.surface}</div>
            </div>
            <button onClick={e => { e.stopPropagation(); onToggleFav(court.id); }}
              className="bg-transparent border-0 text-xl cursor-pointer pl-2">
              {favorites.includes(court.id) ? '❤️' : '🤍'}
            </button>
          </div>
          <div className="flex items-center gap-[10px] mt-[10px]">
            <div className={`text-xs px-[10px] py-[3px] rounded-full font-semibold ${crowdClasses[court.crowd]}`}>
              ● {crowdLabel[court.crowd]}
            </div>
            {court.lighting && <div className="text-xs text-amber-400 bg-amber-50 px-[10px] py-[3px] rounded-full font-semibold">💡 Lit</div>}
            <div className="ml-auto text-[13px] font-bold text-slate-900">⭐ {court.rating}</div>
            <div className="text-[11px] text-slate-400">({court.reviews})</div>
          </div>
        </div>
      ))}
    </div>
  );
}

function App() {
  const [filter, setFilter] = React.useState({ surface: 'all', lighting: 'all', crowd: 'all' });
  const [selected, setSelected] = React.useState(null);
  const [favorites, setFavorites] = React.useState([1]);

  const filtered = COURTS.filter(c =>
    (filter.surface === 'all' || c.surface === filter.surface) &&
    (filter.lighting === 'all' || (filter.lighting === 'yes') === c.lighting) &&
    (filter.crowd === 'all' || c.crowd === filter.crowd)
  );
  const toggleFav = (id) => setFavorites(prev => prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]);

  return (
    <div className="min-h-screen bg-slate-50 max-w-[390px] mx-auto font-sans">
      <div className="bg-white px-5 pt-4 border-b border-slate-100">
        <div className="flex justify-between items-center mb-3">
          <div className="text-[22px] font-bold text-slate-900">Courts Near You</div>
          <div className="text-[13px] text-blue-500 font-semibold">📍 Seoul</div>
        </div>
        <div className="flex items-center bg-slate-100 rounded-xl px-[14px] py-[10px] mb-[14px] gap-2">
          <span className="text-base">🔍</span>
          <input placeholder="Search courts..." className="border-0 bg-transparent outline-none text-sm text-gray-700 flex-1" />
        </div>
        <ApplyCourtFilters filter={filter} onChange={setFilter} />
      </div>
      <CourtMapView courts={filtered} selected={selected} onSelect={setSelected} />
      <CourtList courts={filtered} selected={selected} onSelect={setSelected} favorites={favorites} onToggleFav={toggleFav} />
    </div>
  );
}

const GAMES = [
  { id: 1, court: 'Riverside Park Court', host: 'Alex K.', time: '6:00 PM', date: 'Today', slots: 3, total: 10, level: 'Casual', hostAvatar: '🧑' },
  { id: 2, court: 'Olympic Park Indoor', host: 'Jason M.', time: '7:30 PM', date: 'Today', slots: 1, total: 8, level: 'Competitive', hostAvatar: '👨' },
  { id: 3, court: 'Mapo Sports Complex', host: 'Chris L.', time: '10:00 AM', date: 'Tomorrow', slots: 5, total: 10, level: 'Casual', hostAvatar: '🧔' },
  { id: 4, court: 'Hangang Court B', host: 'Sam P.', time: '4:00 PM', date: 'Tomorrow', slots: 2, total: 6, level: '3-on-3', hostAvatar: '👦' },
];

function GameList({ games, joinedIds, onJoin }) {
  const levelClasses = { Casual: 'text-emerald-500 border-emerald-500', Competitive: 'text-red-500 border-red-500', '3-on-3': 'text-violet-500 border-violet-500' };
  return (
    <div data-dg-component="gameList" className="px-4 pt-3 pb-[100px]">
      {games.length === 0 && (
        <div className="text-center py-10 text-slate-400">
          <div className="text-[36px] mb-3">🏀</div>
          <div className="text-[15px] font-semibold">No games yet</div>
          <div className="text-[13px] mt-1">Join a game or create one!</div>
        </div>
      )}
      {games.map(game => (
        <div key={game.id} className="bg-white rounded-[18px] p-4 mb-3 shadow-sm">
          <div className="flex justify-between items-start mb-[10px]">
            <div>
              <div className="text-[15px] font-bold text-slate-900">{game.court}</div>
              <div className="text-xs text-slate-400 mt-0.5">{game.date} at {game.time}</div>
            </div>
            <span className={`text-xs font-semibold bg-slate-50 px-[10px] py-1 rounded-full border ${levelClasses[game.level] || 'text-slate-500 border-slate-200'}`}>
              {game.level}
            </span>
          </div>
          <div className="flex items-center gap-[10px]">
            <div className="flex items-center gap-[6px] text-[13px] text-slate-500">
              <span className="text-lg">{game.hostAvatar}</span>
              <span>{game.host}</span>
            </div>
            <div className="ml-auto flex items-center gap-2">
              <div className={`text-[13px] font-semibold ${game.slots <= 1 ? 'text-red-500' : 'text-emerald-500'}`}>
                {game.slots} slot{game.slots !== 1 ? 's' : ''} left
              </div>
              <button onClick={() => onJoin(game.id)}
                disabled={game.slots === 0 && !joinedIds.includes(game.id)}
                className={`px-4 py-[7px] rounded-full border-0 cursor-pointer text-[13px] font-bold transition-all duration-150 ${joinedIds.includes(game.id) ? 'bg-red-50 text-red-500' : 'bg-blue-50 text-blue-500'}`}>
                {joinedIds.includes(game.id) ? 'Leave' : 'Join'}
              </button>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

function CreateGame({ onClick }) {
  return (
    <button data-dg-component="createGame" onClick={onClick}
      className="fixed bottom-7 right-7 flex items-center gap-2 bg-gradient-to-br from-orange-500 to-red-500 text-white border-0 rounded-full px-5 py-[14px] text-sm font-bold cursor-pointer shadow-[0_4px_14px_rgba(239,68,68,0.35)]">
      🏀 Create Game
    </button>
  );
}

function App() {
  const [tab, setTab] = React.useState('open');
  const [showCreate, setShowCreate] = React.useState(false);
  const [joined, setJoined] = React.useState([]);

  const myGames = GAMES.filter(g => joined.includes(g.id));
  const displayed = tab === 'open' ? GAMES : myGames;
  const handleJoin = (id) => setJoined(prev => prev.includes(id) ? prev.filter(j => j !== id) : [...prev, id]);

  return (
    <div className="min-h-screen bg-slate-50 max-w-[390px] mx-auto font-sans">
      <div className="bg-white px-5 pt-4 border-b border-slate-100">
        <div className="text-[22px] font-bold text-slate-900 mb-[14px]">Games</div>
        <div className="flex bg-slate-100 rounded-xl p-1">
          {[['open', 'Open Games'], ['mine', 'My Games']].map(([key, label]) => (
            <button key={key} onClick={() => setTab(key)}
              className={`flex-1 py-2 rounded-[9px] border-0 cursor-pointer text-[13px] font-semibold transition-all duration-150 ${tab === key ? 'bg-white text-slate-900 shadow-sm' : 'bg-transparent text-slate-500'}`}>
              {label} {key === 'mine' && joined.length > 0 && `(${joined.length})`}
            </button>
          ))}
        </div>
        <div className="h-[14px]" />
      </div>
      <GameList games={displayed} joinedIds={joined} onJoin={handleJoin} />
      <CreateGame onClick={() => setShowCreate(true)} />
      {showCreate && (
        <div className="fixed inset-0 bg-black/35 flex items-end z-50" onClick={() => setShowCreate(false)}>
          <div className="bg-white rounded-t-3xl px-5 pt-6 pb-8 w-full" onClick={e => e.stopPropagation()}>
            <div className="text-lg font-bold mb-5">🏀 Create Game</div>
            {[['Court', 'Riverside Park Court'], ['Date & Time', 'Today, 6:00 PM'], ['Max Players', '10'], ['Level', 'Casual']].map(([label, val]) => (
              <div key={label} className="mb-[14px]">
                <div className="text-xs text-slate-500 font-semibold mb-[5px]">{label}</div>
                <div className="border-[1.5px] border-slate-200 rounded-xl px-[14px] py-[11px] text-sm text-gray-700">{val}</div>
              </div>
            ))}
            <button onClick={() => setShowCreate(false)} className="w-full bg-gradient-to-br from-orange-500 to-red-500 text-white border-0 rounded-[14px] py-[15px] text-[15px] font-bold cursor-pointer mt-1">
              Create Game
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
